class Padz < Formula
  desc "An ergonomic, context-aware scratch pad for the terminal — a good Unix citizen"
  homepage "https://github.com/arthur-debert/padz"
  version "1.8.0-rc.3"
  license "MIT"

  on_macos do
    on_arm do
      url "https://github.com/arthur-debert/padz/releases/download/v1.8.0-rc.3/padz-aarch64-apple-darwin.tar.gz"
      sha256 "600572accb9c45554d3404c44142c714a82ce4c3788fb3030d41a0ffb4c159c7"
    end
    on_intel do
      url "https://github.com/arthur-debert/padz/releases/download/v1.8.0-rc.3/padz-x86_64-apple-darwin.tar.gz"
      sha256 "3112544bc19f23b735b8317fb1335930b915cacfc12d63cad1a92a85401c7b9e"
    end
  end

  on_linux do
    on_intel do
      url "https://github.com/arthur-debert/padz/releases/download/v1.8.0-rc.3/padz-x86_64-linux-gnu.tar.gz"
      sha256 "8a495235d0ecb4008cf5114219263c7c0bee30b376d5bbadcece4f453779fbdc"
    end
    on_arm do
      url "https://github.com/arthur-debert/padz/releases/download/v1.8.0-rc.3/padz-aarch64-linux-gnu.tar.gz"
      sha256 "89cde0580e437753ead51d070517ef205c6a8abcc2c39a377c47cd7c9ddff5be"
    end
  end

  def install
    # Homebrew cd's into the single top-level directory when the tarball
    # has one — which ours does (`padz-<target>/padz`).
    # The Dir glob fallback covers reuse with flat tarballs or any other
    # packaging layout.
    executable = if File.exist?("padz")
      "padz"
    else
      Dir["*/padz"].find { |path| File.file?(path) }
    end
    raise "Could not find padz in extracted archive" unless executable
    bin.install executable

    # Generate completion scripts from the binary itself so they always
    # match the clap_complete wire protocol the binary implements.
    # padz's completion CLI is `padz completion --shell X print`,
    # which doesn't match any of Homebrew's generate_completions_from_executable
    # presets, so invoke manually.
    [
      [bash_completion/"padz",       "bash"],
      [zsh_completion/"_padz",       "zsh"],
      [fish_completion/"padz.fish",  "fish"],
    ].each do |path, shell|
      path.write Utils.safe_popen_read(bin/"padz", "completion", "--shell", shell, "print")
    end
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/padz --version")
  end
end
